{
  "name": "specify",
  "version": "0.1.0",
  "description": "Spec-driven functional verification for web applications",
  "commands": [
    {
      "name": "spec validate",
      "description": "Validate a spec against captured data",
      "parameters": [
        {
          "name": "--spec",
          "type": "string",
          "required": true,
          "description": "Path to spec file (or - for stdin)"
        },
        {
          "name": "--capture",
          "type": "string",
          "required": true,
          "description": "Path to capture directory"
        },
        {
          "name": "--output",
          "type": "string",
          "required": false,
          "description": "Output directory for report files"
        },
        {
          "name": "--history-dir",
          "type": "string",
          "required": false,
          "description": "Directory to save report history"
        }
      ]
    },
    {
      "name": "spec generate",
      "description": "Generate a spec from capture data",
      "parameters": [
        {
          "name": "--input",
          "type": "string",
          "required": true,
          "description": "Path to capture directory"
        },
        {
          "name": "--output",
          "type": "string",
          "required": false,
          "description": "Output file path"
        },
        {
          "name": "--name",
          "type": "string",
          "required": false,
          "description": "Spec name"
        },
        {
          "name": "--smart",
          "type": "boolean",
          "required": false,
          "description": "Use smart generation"
        }
      ]
    },
    {
      "name": "spec refine",
      "description": "Refine a spec interactively or using a gap report",
      "parameters": [
        {
          "name": "--spec",
          "type": "string",
          "required": true,
          "description": "Path to spec file"
        },
        {
          "name": "--report",
          "type": "string",
          "required": false,
          "description": "Path to gap report JSON (if omitted, enters interactive mode)"
        },
        {
          "name": "--url",
          "type": "string",
          "required": false,
          "description": "URL to crawl for context (interactive mode only)"
        },
        {
          "name": "--output",
          "type": "string",
          "required": false,
          "description": "Output file path"
        }
      ]
    },
    {
      "name": "agent run",
      "description": "Run autonomous agent-driven verification",
      "parameters": [
        {
          "name": "--spec",
          "type": "string",
          "required": true,
          "description": "Path to spec file (or - for stdin)"
        },
        {
          "name": "--url",
          "type": "string",
          "required": true,
          "description": "Target base URL"
        },
        {
          "name": "--headed",
          "type": "boolean",
          "required": false,
          "description": "Run browser visibly"
        },
        {
          "name": "--output",
          "type": "string",
          "required": false,
          "description": "Output directory"
        },
        {
          "name": "--explore",
          "type": "boolean",
          "required": false,
          "description": "Enable adaptive exploration"
        },
        {
          "name": "--max-exploration-rounds",
          "type": "number",
          "required": false,
          "description": "Max exploration rounds",
          "default": 2
        },
        {
          "name": "--timeout",
          "type": "number",
          "required": false,
          "description": "Timeout in ms",
          "default": 300000
        },
        {
          "name": "--no-setup",
          "type": "boolean",
          "required": false,
          "description": "Skip setup hooks"
        },
        {
          "name": "--no-teardown",
          "type": "boolean",
          "required": false,
          "description": "Skip teardown hooks"
        },
        {
          "name": "--no-screenshots",
          "type": "boolean",
          "required": false,
          "description": "Disable screenshots"
        }
      ]
    },
    {
      "name": "cli run",
      "description": "Run CLI verification against a spec",
      "parameters": [
        {
          "name": "--spec",
          "type": "string",
          "required": true,
          "description": "Path to spec file (or - for stdin)"
        },
        {
          "name": "--output",
          "type": "string",
          "required": false,
          "description": "Output directory for report files"
        }
      ]
    },
    {
      "name": "report diff",
      "description": "Diff two gap reports",
      "parameters": [
        {
          "name": "--a",
          "type": "string",
          "required": true,
          "description": "Path to first report"
        },
        {
          "name": "--b",
          "type": "string",
          "required": true,
          "description": "Path to second report"
        }
      ]
    },
    {
      "name": "report stats",
      "description": "Show statistical confidence from history",
      "parameters": [
        {
          "name": "--history-dir",
          "type": "string",
          "required": true,
          "description": "Path to history directory"
        }
      ]
    },
    {
      "name": "schema",
      "description": "Output JSON Schema for spec, report, or commands",
      "parameters": [
        {
          "name": "target",
          "type": "string",
          "required": true,
          "description": "Schema target: spec, report, or commands"
        }
      ]
    },
    {
      "name": "spec import",
      "description": "Import existing e2e tests as spec items",
      "parameters": [
        {
          "name": "--from",
          "type": "string",
          "required": true,
          "description": "Path to test file or directory"
        },
        {
          "name": "--framework",
          "type": "string",
          "required": false,
          "description": "Test framework: playwright or cypress (auto-detected if omitted)"
        },
        {
          "name": "--output",
          "type": "string",
          "required": false,
          "description": "Output path for generated spec file"
        }
      ]
    },
    {
      "name": "spec export",
      "description": "Export spec items as e2e test code",
      "parameters": [
        {
          "name": "--spec",
          "type": "string",
          "required": true,
          "description": "Path to spec file (or - for stdin)"
        },
        {
          "name": "--framework",
          "type": "string",
          "required": true,
          "description": "Target framework: playwright or cypress"
        },
        {
          "name": "--output",
          "type": "string",
          "required": false,
          "description": "Output directory for generated test files"
        },
        {
          "name": "--split-files",
          "type": "boolean",
          "required": false,
          "description": "Generate one file per page/flow"
        }
      ]
    },
    {
      "name": "spec evolve",
      "description": "Evolve a spec from PR changes or interactive gap analysis",
      "parameters": [
        {
          "name": "--spec",
          "type": "string",
          "required": true,
          "description": "Path to spec file (or - for stdin)"
        },
        {
          "name": "--pr",
          "type": "string",
          "required": false,
          "description": "PR number or URL to analyze (omit for interactive mode)"
        },
        {
          "name": "--repo",
          "type": "string",
          "required": false,
          "description": "GitHub repo (owner/repo) if not inferrable from PR URL"
        }
      ],
      "examples": [
        "specify spec evolve --spec spec.yaml --pr 42",
        "specify spec evolve --spec spec.yaml --pr https://github.com/org/repo/pull/42",
        "specify spec evolve --spec spec.yaml"
      ]
    },
    {
      "name": "spec sync",
      "description": "Compare spec against existing e2e tests bidirectionally",
      "parameters": [
        {
          "name": "--spec",
          "type": "string",
          "required": true,
          "description": "Path to spec file (or - for stdin)"
        },
        {
          "name": "--tests",
          "type": "string",
          "required": true,
          "description": "Path to test directory"
        },
        {
          "name": "--framework",
          "type": "string",
          "required": false,
          "description": "Test framework: playwright or cypress (auto-detected if omitted)"
        }
      ]
    },
    {
      "name": "spec lint",
      "description": "Validate spec structure without captures (schema + semantic checks)",
      "parameters": [
        {
          "name": "--spec",
          "type": "string",
          "required": true,
          "description": "Path to spec file (or - for stdin)"
        }
      ]
    },
    {
      "name": "spec guide",
      "description": "Output authoring guide (schema, examples, patterns) for LLM spec writers",
      "parameters": []
    },
    {
      "name": "mcp",
      "description": "Start MCP (Model Context Protocol) server for LLM tool integration",
      "parameters": [
        {
          "name": "--http",
          "type": "boolean",
          "required": false,
          "description": "Use HTTP transport instead of stdio (for remote access)"
        },
        {
          "name": "--port",
          "type": "number",
          "required": false,
          "description": "Port for HTTP transport (default: 8080)"
        },
        {
          "name": "--host",
          "type": "string",
          "required": false,
          "description": "Host to bind to (default: 0.0.0.0)"
        }
      ],
      "examples": [
        "specify mcp",
        "specify mcp --http --port 3001",
        "{\"mcpServers\": {\"specify\": {\"command\": \"specify\", \"args\": [\"mcp\"]}}}",
        "{\"mcpServers\": {\"specify\": {\"url\": \"http://host:8080/mcp\"}}}"
      ]
    },
    {
      "name": "human",
      "description": "Interactive mode — context-aware wizard that detects project state and guides you",
      "parameters": [
        {
          "name": "--from-capture",
          "type": "string",
          "required": false,
          "description": "Pre-populate wizard from capture directory"
        }
      ],
      "examples": [
        "specify human",
        "specify human shell --spec spec.yaml",
        "specify human watch --spec spec.yaml --url http://localhost:3000"
      ]
    },
    {
      "name": "human shell",
      "description": "Interactive REPL for iterative spec development with tab completion",
      "parameters": [
        {
          "name": "--spec",
          "type": "string",
          "required": false,
          "description": "Initial spec to load"
        },
        {
          "name": "--url",
          "type": "string",
          "required": false,
          "description": "Target URL"
        }
      ]
    },
    {
      "name": "human watch",
      "description": "Live TUI dashboard for monitoring agent runs and spec status",
      "parameters": [
        {
          "name": "--spec",
          "type": "string",
          "required": true,
          "description": "Path to spec file"
        },
        {
          "name": "--url",
          "type": "string",
          "required": true,
          "description": "Target URL"
        }
      ]
    }
  ],
  "global_options": [
    {
      "name": "--json",
      "description": "Force JSON output"
    },
    {
      "name": "--output-format",
      "type": "string",
      "description": "Output format: json|text|markdown|ndjson"
    },
    {
      "name": "--fields",
      "type": "string",
      "description": "Comma-separated field paths to select from output"
    },
    {
      "name": "--quiet",
      "description": "Suppress non-essential output"
    }
  ],
  "exit_codes": {
    "0": "success",
    "1": "assertion_failure",
    "2": "all_untested",
    "10": "parse_error",
    "11": "network_error",
    "12": "timeout",
    "13": "assumption_failure",
    "14": "browser_error"
  },
  "hint": "Run \"specify schema commands\" for full parameter schemas. Run \"specify human\" for interactive mode."
}

