{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "Specify Spec",
  "description": "Computational spec format for functional verification of web applications.",
  "type": "object",
  "required": [
    "version",
    "name"
  ],
  "additionalProperties": false,
  "properties": {
    "version": {
      "type": "string",
      "description": "Spec format version."
    },
    "name": {
      "type": "string",
      "description": "Human-readable name for this spec."
    },
    "description": {
      "type": "string",
      "description": "Optional description of what this spec covers."
    },
    "pages": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/PageSpec"
      }
    },
    "flows": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/FlowSpec"
      }
    },
    "cli": {
      "$ref": "#/$defs/CliSpec"
    },
    "hooks": {
      "$ref": "#/$defs/HooksSpec"
    },
    "variables": {
      "type": "object",
      "additionalProperties": {
        "type": "string"
      }
    },
    "assumptions": {
      "type": "array",
      "items": {
        "$ref": "#/$defs/Assumption"
      },
      "description": "Preconditions that must hold for this spec to be validly tested."
    },
    "defaults": {
      "$ref": "#/$defs/DefaultProperties"
    }
  },
  "$defs": {
    "PageSpec": {
      "type": "object",
      "required": [
        "id",
        "path"
      ],
      "additionalProperties": false,
      "properties": {
        "id": {
          "type": "string"
        },
        "path": {
          "type": "string"
        },
        "title": {
          "type": "string"
        },
        "visual_assertions": {
          "type": "array",
          "items": {
            "$ref": "#/$defs/VisualAssertion"
          }
        },
        "expected_requests": {
          "type": "array",
          "items": {
            "$ref": "#/$defs/ExpectedRequest"
          }
        },
        "console_expectations": {
          "type": "array",
          "items": {
            "$ref": "#/$defs/ConsoleExpectation"
          }
        },
        "scenarios": {
          "type": "array",
