    "content": "import { test, expect } from '@playwright/test';

test.beforeAll(async () => {
  // Create test user
  await fetch('{{base_url}}/api/test/users', {
    method: 'POST',
    body: JSON.stringify({"email":"test@example.com","password":"test123"}),
  });
  // Seed product catalog
  await fetch('{{base_url}}/api/test/seed-products', {
    method: 'POST',
    body: JSON.stringify({"count":10}),
  });
});

test.afterAll(async () => {
  // Delete test user
  await fetch('{{base_url}}/api/test/users/{{test_user.id}}', { method: 'DELETE' });
  // Clean up test orders
  // Shell: curl -X DELETE {{base_url}}/api/test/orders?user={{test_user.id}}
});

test.describe('product-list', () => {
  test('product-list — visual assertions', async ({ page }) => {
    await page.goto('${TARGET_BASE_URL}/products');
    await expect(page.locator('.product-grid')).toBeVisible();
    expect(await page.locator('.product-card').count()).toBeGreaterThanOrEqual(1);
  });
});

test.describe('cart', () => {
  test('cart — visual assertions', async ({ page }) => {
    await page.goto('${TARGET_BASE_URL}/cart');
    await expect(page.locator('.cart-items')).toBeVisible();
    await expect(page.locator('.cart-total')).toBeVisible();
    await expect(page.locator('[data-testid=checkout-button]')).toBeVisible();
  });
});

test.describe('checkout', () => {
  test('checkout — visual assertions', async ({ page }) => {
    await page.goto('${TARGET_BASE_URL}/checkout');
    await expect(page.locator('form.checkout-form')).toBeVisible();
    await expect(page.locator('#card-number')).toBeVisible();
    await expect(page.locator('.order-summary')).toBeVisible();
  });
});

test.describe('confirmation', () => {
  test('confirmation — visual assertions', async ({ page }) => {
    await page.goto('${TARGET_BASE_URL}/order/confirmation');
    await expect(page.locator('.confirmation-message')).toBeVisible();
    await expect(page.locator('.order-number')).toHaveText(/^ORD-\d+$/);
  });
});

test('browse-to-checkout — User browses products, adds to cart, and completes checkout', async ({ page }) => {
  await page.goto('${TARGET_BASE_URL}/products');  // Start at product listing
  await expect(page.locator('.product-grid')).toBeVisible();
  expect(await page.locator('.product-card').count()).toBeGreaterThanOrEqual(1);
  await page.locator('.product-card:first-child .add-to-cart').click();  // Add first product to cart
  await page.waitForRequest('/api/cart/items');  // Add-to-cart API call completes
  await expect(page.locator('.cart-badge')).toBeVisible();  // Cart badge shows item count
  await page.goto('${TARGET_BASE_URL}/cart');  // Go to cart page
  await expect(page.locator('.cart-items')).toBeVisible();
  await expect(page.locator('.cart-total')).toBeVisible();
