    "filePath": "login-page-spec.spec.ts",
    "content": "import { test, expect } from '@playwright/test';

test.describe('login', () => {
  test('login — visual assertions', async ({ page }) => {
    await page.goto('${TARGET_BASE_URL}/login');
    await expect(page.locator('form')).toBeVisible();
    await expect(page.locator('#email')).toBeVisible();
    await expect(page.locator('#password')).toBeVisible();
    await expect(page.locator('button[type=submit]')).toBeVisible();
    await expect(page.locator('button[type=submit]')).toContainText('Log In');
  });

  test('successful-login — User logs in with valid credentials', async ({ page }) => {
    await page.goto('${TARGET_BASE_URL}/login');
    await page.locator('#email').fill('{{test_user.email}}');
    await page.locator('#password').fill('{{test_user.password}}');
    await page.locator('button[type=submit]').click();
    await page.waitForURL('/dashboard');  // Redirects to dashboard after login
  });

  test('failed-login — User sees error with invalid credentials', async ({ page }) => {
    await page.goto('${TARGET_BASE_URL}/login');
    await page.locator('#email').fill('wrong@example.com');
    await page.locator('#password').fill('badpassword');
    await page.locator('button[type=submit]').click();
    await expect(page.locator('.error-message')).toBeVisible();  // Error message is displayed
  });
});
",
    "framework": "playwright",
    "sourceSpecIds": [
      "login"
    ]
  }
]

